(function(){'use strict';const STORAGE_KEY = 'sgp-theme';const DEFAULT_THEME = 'light';function applyTheme(){const html = document.documentElement;const savedTheme = localStorage.getItem(STORAGE_KEY)|| DEFAULT_THEME;html.setAttribute('data-theme', savedTheme);return savedTheme;}const currentTheme = applyTheme();function setupThemeToggle(){const themeToggle = document.getElementById('theme-toggle');const themeIcon = document.getElementById('theme-icon');const html = document.documentElement;if(themeIcon){themeIcon.className = currentTheme === 'dark' ? 'fas fa-sun' : 'fas fa-moon';}if(themeToggle){themeToggle.addEventListener('click', function(){const current = html.getAttribute('data-theme');const newTheme = current === 'light' ? 'dark' : 'light';html.setAttribute('data-theme', newTheme);localStorage.setItem(STORAGE_KEY, newTheme);if(themeIcon){themeIcon.className = newTheme === 'dark' ? 'fas fa-sun' : 'fas fa-moon';}themeToggle.style.transform = 'scale(0.85)';setTimeout(function(){themeToggle.style.transform = '';}, 200);});}}if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded', setupThemeToggle);}else{setupThemeToggle();}})();